noncompliant:
void badFunction() {
    // Noncompliant: dynamic allocation with new
    int* ptr = new int[1000];
    // ... use ptr
    delete[] ptr; // Manual memory management required
}

void anotherBadFunction() {
    // Noncompliant: C-style allocation
    void* memory = malloc(sizeof(int) * 1000);
    // ... use memory
    free(memory); // Manual cleanup required
}

compliant:
void goodFunction() {
    // Compliant: stack allocation
    int arr[1000];
    // ... use arr
    // Automatic cleanup when leaving scope
}

void betterFunction() {
    // Compliant: use containers for dynamic size
    std::vector<int> vec(1000);
    // ... use vec
    // Automatic memory management
}

void modernFunction() {
    // Compliant: smart pointers when dynamic allocation needed
    auto ptr = std::make_unique<int[]>(1000);
    // ... use ptr
    // Automatic cleanup
}
